import React from 'react'
import { useStore } from '../store'

export default function ContactList(){
  const {contacts, openChat} = useStore()

  return (
    <aside className="w-64 bg-gray-100 p-2">
      <h3 className="font-bold mb-2">Contacts</h3>
      <ul>
        {contacts.map(c=> (
          <li key={c.id} className="p-2 flex justify-between items-center">
            <div>
              <div className="text-sm">{c.name}</div>
              <div className="text-xs text-gray-500">{c.online? 'Online' : 'Offline'}</div>
            </div>
            <button onClick={()=>openChat({id: c.id, user: c.name})} className="text-blue-600">Chat</button>
          </li>
        ))}
      </ul>
    </aside>
  )
}
